1:import type { Context } from 'hono';
3:/** A page contributed by a plugin kit or apparatus supportKit. */
4:export interface PageContribution {
5:  /** Unique page ID — becomes the URL segment: /pages/{id}/ */
6:  id: string;
7:  /** Human-readable title used in navigation. */
8:  title: string;
9:  /**
10:   * Path to the directory containing the page's static assets,
11:   * relative to the contributing package's root in node_modules.
12:   * Must contain an index.html entry point.
13:   */
14:  dir: string;
15:}
17:/** A custom route contributed by a plugin kit or apparatus supportKit. */
18:export interface RouteContribution {
19:  /** HTTP method (uppercase): 'GET', 'POST', 'DELETE', etc. */
20:  method: string;
21:  /** Hono path pattern. Must begin with /api/. */
22:  path: string;
23:  /** Hono handler function. */
24:  handler: (c: Context) => Response | Promise<Response>;
25:}
27:/** Kit contribution interface — consumed by the Oculus. */
28:export interface OculusKit {
29:  pages?: PageContribution[];
30:  routes?: RouteContribution[];
31:}
33:/** The Oculus configuration from guild.json under 'oculus'. */
34:export interface OculusConfig {
35:  /** Port to listen on. Default: 7470. */
36:  port?: number;
37:}
39:/** The Oculus's public API, exposed via provides. */
40:export interface OculusApi {
41:  /** The port the server is listening on. */
42:  port(): number;
43:}

