52:function makePageDir(parentDir: string, name: string, html: string): string {
53:  const dir = path.join(parentDir, name);
54:  fs.mkdirSync(dir, { recursive: true });
55:  fs.writeFileSync(path.join(dir, 'index.html'), html);
56:  return dir;
57:}
59:function buildTestContext(): {
60:  ctx: StartupContext;
61:  fire: (event: string, ...args: unknown[]) => Promise<void>;
62:} {
63:  const handlers = new Map<string, Array<(...args: unknown[]) => void | Promise<void>>>();
65:  const ctx: StartupContext = {
66:    on(event, handler) {
67:      const list = handlers.get(event) ?? [];
68:      list.push(handler);
69:      handlers.set(event, list);
70:    },
71:  };
73:  async function fire(event: string, ...args: unknown[]): Promise<void> {
74:    for (const h of handlers.get(event) ?? []) {
75:      await h(...args);
76:    }
77:  }
79:  return { ctx, fire };
80:}
82:function mockKit(id: string, tools: unknown[], pages?: PageContribution[], routes?: RouteContribution[]): LoadedKit {
83:  return {
84:    packageName: `@test/${id}`,
