57: *               by walking up from cwd until guild.json is found.
58: * @returns The initialized Guild — the same object guild() returns.
59: */
60:export async function createGuild(root?: string): Promise<Guild> {
61:  const guildRoot = root ?? findGuildRoot();
62:  const config = readGuildConfig(guildRoot);
64:  const kits:        LoadedKit[]        = [];
65:  const apparatuses: LoadedApparatus[]  = [];
66:  const eventHandlers: EventHandlerMap = new Map();
68:  // ── Load phase ─────────────────────────────────────────────────────
70:  for (const pluginId of config.plugins) {
71:    const packageName = resolvePackageNameForPluginId(guildRoot, pluginId);
72:    if (!packageName) {
73:      console.warn(`[arbor] No package found in package.json for plugin "${pluginId}" — skipping`);
74:      continue;
75:    }
77:    const { version } = readGuildPackageJson(guildRoot, packageName);
79:    try {
80:      const entryPath = resolveGuildPackageEntry(guildRoot, packageName);
81:      const mod = await import(entryPath) as { default: unknown };
82:      const raw = mod.default;
84:      if (isApparatus(raw)) {
85:        apparatuses.push({ packageName, id: pluginId, version, apparatus: raw.apparatus });
86:      } else if (isKit(raw)) {
87:        kits.push({ packageName, id: pluginId, version, kit: raw.kit });
88:      } else {
