145:          `No loaded apparatus provides this id. Check guild.json plugins list.`,
146:        );
147:      }
148:      return p as T;
149:    },
151:    config<T = Record<string, unknown>>(pluginId: string): T {
152:      // GuildConfig types only the framework-level keys (name, nexus, plugins, etc.).
153:      // Plugin-specific config sections (e.g. "animator", "stacks") are additional
154:      // top-level keys in guild.json that GuildConfig doesn't model. The cast is safe
