1:/**
2: * Guild lifecycle — pure logic for plugin validation, ordering, and events.
3: *
4: * All functions here operate on in-memory data structures (LoadedKit[],
5: * LoadedApparatus[], Maps) with no I/O. This makes them independently
6: * testable with synthetic fixtures.
7: *
8: * `createGuild()` in arbor.ts is the orchestrator that performs I/O
9: * (config reading, dynamic imports) then delegates to these functions.
10: */
12:import type {
13:  StartupContext,
14:  LoadedKit,
15:  LoadedApparatus,
16:  FailedPlugin,
17:} from '@shardworks/nexus-core';
19:// ── Types ────────────────────────────────────────────────────────────
21:export type EventHandlerMap = Map<
22:  string,
23:  Array<(...args: unknown[]) => void | Promise<void>>
24:>;
26:// ── Validation ───────────────────────────────────────────────────────
28:/**
29: * Validate all `requires` declarations and detect circular dependencies.
30: * Returns an array of FailedPlugin entries describing every problem found.
31: *
32: * Checks:
33: * - Apparatus requires: every named dependency must exist (kit or apparatus).
34: * - Kit requires: every named dependency must be an apparatus (kits can't
35: *   depend on kits).
36: * - Cycle detection: no circular dependency chains among apparatuses.
37: */
38:export function validateRequires(
39:  kits: LoadedKit[],
40:  apparatuses: LoadedApparatus[],
41:): FailedPlugin[] {
42:  const failures: FailedPlugin[] = [];
43:  const failedIds = new Set<string>();
45:  const apparatusIds = new Set(apparatuses.map((a) => a.id));
46:  const allIds = new Set([
47:    ...kits.map((k) => k.id),
48:    ...apparatuses.map((a) => a.id),
49:  ]);
51:  // Check apparatus requires
52:  for (const app of apparatuses) {
53:    for (const dep of app.apparatus.requires ?? []) {
54:      if (!allIds.has(dep)) {
55:        if (!failedIds.has(app.id)) {
56:          failedIds.add(app.id);
57:          failures.push({
58:            id:     app.id,
59:            reason: `"${app.id}" requires "${dep}", which is not installed.`,
60:          });
61:        }
62:      }
63:    }
64:  }
66:  // Check kit requires (must be apparatus names — kits can't depend on kits)
67:  for (const kit of kits) {
68:    for (const dep of kit.kit.requires ?? []) {
69:      if (!apparatusIds.has(dep)) {
70:        if (!failedIds.has(kit.id)) {
71:          failedIds.add(kit.id);
72:          if (!allIds.has(dep)) {
73:            failures.push({
74:              id:     kit.id,
75:              reason: `kit "${kit.id}" requires "${dep}", which is not installed.`,
76:            });
77:          } else {
78:            failures.push({
79:              id:     kit.id,
80:              reason: `kit "${kit.id}" requires "${dep}", but that plugin is a kit, not an apparatus. Kit requires must name apparatus plugins.`,
81:            });
82:          }
83:        }
84:      }
85:    }
86:  }
88:  // Detect circular dependencies among apparatuses
89:  const visiting = new Set<string>();
90:  const visited = new Set<string>();
91:  const cycleParticipants = new Set<string>();
93:  function visit(id: string, chain: string[]): void {
94:    if (visited.has(id)) return;
95:    if (visiting.has(id)) {
96:      // Back-edge detected — extract cycle participants from chain
97:      const cycleStart = chain.indexOf(id);
98:      const cycleNodes = cycleStart >= 0 ? chain.slice(cycleStart) : [...chain];
99:      cycleNodes.push(id);
100:      for (const node of cycleNodes) {
101:        cycleParticipants.add(node);
102:      }
103:      return;
104:    }
105:    visiting.add(id);
106:    const app = apparatuses.find((a) => a.id === id);
107:    if (app) {
108:      for (const dep of app.apparatus.requires ?? []) {
109:        visit(dep, [...chain, id]);
110:      }
111:    }
112:    visiting.delete(id);
113:    visited.add(id);
114:  }
116:  for (const app of apparatuses) {
117:    visit(app.id, []);
118:  }
120:  for (const id of cycleParticipants) {
121:    if (!failedIds.has(id)) {
122:      failedIds.add(id);
123:      failures.push({
124:        id,
125:        reason: `"${id}" is part of a circular dependency chain.`,
126:      });
127:    }
128:  }
130:  return failures;
131:}
133:// ── Cascade filtering ─────────────────────────────────────────────────
135:/**
136: * Remove plugins that transitively depend on any failed plugin.
137: *
138: * Iterates until stable, cascading failures through the dependency graph.
139: * Returns healthy plugins and any newly-cascaded failures.
140: */
141:export function filterFailedPlugins(
142:  kits: LoadedKit[],
143:  apparatuses: LoadedApparatus[],
144:  rootFailures: FailedPlugin[],
145:): { kits: LoadedKit[]; apparatuses: LoadedApparatus[]; cascaded: FailedPlugin[] } {
146:  const failedIds = new Set<string>(rootFailures.map((f) => f.id));
147:  const cascaded: FailedPlugin[] = [];
149:  // Apparatus cascade: iterate until no new failures
150:  let changed = true;
151:  while (changed) {
152:    changed = false;
153:    for (const app of apparatuses) {
154:      if (failedIds.has(app.id)) continue;
155:      for (const dep of app.apparatus.requires ?? []) {
156:        if (failedIds.has(dep)) {
157:          failedIds.add(app.id);
158:          cascaded.push({
159:            id:     app.id,
160:            reason: `"${app.id}" depends on failed plugin "${dep}".`,
161:          });
162:          changed = true;
163:          break;
164:        }
165:      }
166:    }
167:  }
169:  // Kit cascade: single pass (kits can't depend on other kits)
170:  for (const kit of kits) {
171:    if (failedIds.has(kit.id)) continue;
172:    for (const dep of kit.kit.requires ?? []) {
173:      if (failedIds.has(dep)) {
174:        failedIds.add(kit.id);
175:        cascaded.push({
176:          id:     kit.id,
177:          reason: `"${kit.id}" depends on failed plugin "${dep}".`,
178:        });
179:        break;
180:      }
181:    }
182:  }
184:  return {
185:    kits:        kits.filter((k) => !failedIds.has(k.id)),
186:    apparatuses: apparatuses.filter((a) => !failedIds.has(a.id)),
187:    cascaded,
188:  };
189:}
191:// ── Dependency ordering ──────────────────────────────────────────────
193:/**
194: * Sort apparatuses in dependency-resolved order using topological sort.
195: * validateRequires() must be called first to ensure the graph is acyclic.
196: */
197:export function topoSort(apparatuses: LoadedApparatus[]): LoadedApparatus[] {
198:  const sorted: LoadedApparatus[] = [];
199:  const visited = new Set<string>();
201:  function visit(id: string): void {
202:    if (visited.has(id)) return;
203:    const app = apparatuses.find((a) => a.id === id);
204:    if (!app) return;
205:    for (const dep of app.apparatus.requires ?? []) {
206:      visit(dep);
207:    }
208:    visited.add(id);
209:    sorted.push(app);
210:  }
212:  for (const app of apparatuses) {
213:    visit(app.id);
214:  }
216:  return sorted;
217:}
219:// ── Startup warnings ─────────────────────────────────────────────────
221:/**
222: * Collect advisory warnings for kit contributions that no apparatus
223: * consumes, and for missing recommended apparatuses.
224: *
225: * Returns an array of warning strings. The caller decides how to emit
226: * them (console.warn, logger, etc.).
227: */
228:export function collectStartupWarnings(
229:  kits:        LoadedKit[],
230:  apparatuses: LoadedApparatus[],
231:): string[] {
232:  const warnings: string[] = [];
233:  const consumedTypes = new Set<string>();
234:  const installedIds  = new Set(apparatuses.map((a) => a.id));
236:  for (const app of apparatuses) {
237:    for (const token of app.apparatus.consumes ?? []) {
238:      consumedTypes.add(token);
239:    }
240:  }
242:  // Check apparatus recommends
243:  for (const app of apparatuses) {
244:    for (const rec of app.apparatus.recommends ?? []) {
245:      if (!installedIds.has(rec)) {
246:        warnings.push(
247:          `[arbor] warn: "${app.id}" recommends "${rec}" but it is not installed.`,
248:        );
249:      }
250:    }
251:  }
253:  for (const kit of kits) {
254:    // Check kit recommends
255:    for (const rec of kit.kit.recommends ?? []) {
256:      if (!installedIds.has(rec)) {
257:        warnings.push(
258:          `[arbor] warn: "${kit.id}" recommends "${rec}" but it is not installed.`,

